714	    for (const p of lengthParams) {
715	      const raw = paramDraft[p.key];
716	      const val = raw !== undefined ? Number(raw) : (p.default as number);
717	      if (Number.isFinite(val)) params[p.key] = val;
718	    }
719	    onSave(baseFamilyId, name.trim(), params);
720	  }
721	
722	  return (
723	    <div className="mt-1 space-y-1.5 rounded border border-border bg-background p-2">
724	      <label className={LABEL_CLS}>
725	        Base family
726	        <select
727	          className={INPUT_CLS}
728	          value={baseFamilyId}
729	          onChange={(e) => {
730	            setBaseFamilyId(e.target.value);
731	            setParamDraft({});
732	          }}
733	        >
734	          {families.map((f) => (
735	            <option key={f.id} value={f.id}>
736	              {f.name}
737	            </option>
738	          ))}
739	        </select>
740	      </label>
741	      <label className={LABEL_CLS}>
742	        Type name
743	        <input
744	          className={INPUT_CLS}
745	          value={name}
746	          onChange={(e) => setName(e.target.value)}
747	          placeholder="e.g. Wide fire door"
748	          autoFocus
749	        />
750	      </label>
751	      {lengthParams.map((p) => (
752	        <label key={p.key} className={LABEL_CLS}>
753	          {p.label} (mm)
754	          <input
755	            className={INPUT_CLS}
756	            type="number"
757	            value={paramDraft[p.key] ?? String(p.default as number)}
758	            onChange={(e) => setParamDraft((d) => ({ ...d, [p.key]: e.target.value }))}
759	          />
760	        </label>
761	      ))}
762	      <div className="flex gap-2 pt-0.5">
763	        <button
764	          type="button"
765	          disabled={!name.trim()}
766	          onClick={handleSave}
767	          className="flex-1 rounded border border-border bg-surface-strong px-2 py-0.5 text-[10px] hover:bg-accent-soft disabled:opacity-40"
768	        >
