3	/** Precedence matches server `_resolve_sort_descending` (filters, then grouping). */
4	export function resolveScheduleSortDescending(
5	  filters: Record<string, unknown>,
6	  grouping: Record<string, unknown> | undefined,
7	): boolean {
8	  for (const src of [filters, grouping ?? {}]) {
9	    const v = src.sortDescending ?? src.sort_descending;
10	    if (typeof v === 'boolean') return v;
11	    if (typeof v === 'string' && ['true', '1', 'yes'].includes(v.trim().toLowerCase())) return true;
12	  }
13	  return false;
14	}
15	
16	export function scheduleTotalsReadoutParts(totals: Record<string, unknown> | undefined): string[] {
17	  if (!totals) return [];
18	
19	  const kind = String(totals.kind ?? '');
20	
21	  const parts: string[] = [];
22	
23	  parts.push(`${totals.rowCount ?? totals.row_count ?? '?'} rows`);
24	
25	  if (kind === 'room') {
26	    parts.push(`sum area ${Number(totals.areaM2 ?? 0).toFixed(3)} m2`);
27	    parts.push(`sum perimeter ${Number(totals.perimeterM ?? 0).toFixed(3)} m`);
28	    const tsum = totals.targetAreaM2 ?? totals.target_area_m2;
29	    if (tsum != null && tsum !== '' && Number.isFinite(Number(tsum))) {
30	      parts.push(`sum target ${Number(tsum).toFixed(3)} m²`);
31	    }
32	    const fc = totals.finishCompleteCount ?? totals.finish_complete_count;
33	    if (fc != null && fc !== '' && Number.isFinite(Number(fc))) {
34	      parts.push(`finish OK ${Number(fc)}`);
35	    }
36	    const fm = totals.finishMissingCount ?? totals.finish_missing_count;
37	    if (fm != null && fm !== '' && Number.isFinite(Number(fm))) {
38	      parts.push(`finish missing ${Number(fm)}`);
39	    }
40	    const fps = totals.finishPeerSuggestedCount ?? totals.finish_peer_suggested_count;
41	    if (fps != null && fps !== '' && Number.isFinite(Number(fps))) {
42	      parts.push(`finish peer ${Number(fps)}`);
43	    }
44	  }
45	
46	  if (kind === 'door') {
47	    parts.push(`sum rough opening ${Number(totals.roughOpeningAreaM2 ?? 0).toFixed(6)} m²`);
48	  }
49	
50	  if (kind === 'window') {
51	    parts.push(`avg width ${Number(totals.averageWidthMm ?? 0).toFixed(1)} mm`);
52	    parts.push(`sum rough opening ${Number(totals.roughOpeningAreaM2 ?? 0).toFixed(6)} m²`);
